    },
    qualityGate: {
      maxAttempts: 3,
      minTopicClarity: 70,
      minSatireStrength: 60,
      minMustShowCoverage: 70,
      minVisualCoherence: 65,
      requireTopicRecognizable: true,
      requireSatireRecognizable: true,
      requireConflictRecognizable: true,
      rejectForbiddenElements: true
    },
    workflow: {
      ...currentWorkflow,
      visualStage: $json.visualStage || 'prompt_error',
      visualParseError: $json.visualParseError === true,
      visualDebugReason: $json.visualDebugReason || '',
      imagePromptFound: $json.imagePromptFound === true,
      visualPromptCreatedAt: $json.visualPromptCreatedAt || $now.toISO(),
      visualPromptWorkflowVersion: 'visual-prompt-v3.3-qa-ready'
    }
  });
})() }}

