function getRetryInfo(j) {
  let vj = {};
  try {
    vj = JSON.parse(j.visualJson || '{}');
    if (typeof vj !== 'object') vj = {};
  } catch(e) {}
  const wf = (typeof vj.workflow === 'object' && vj.workflow) ? vj.workflow : {};
  const attempt = Math.max(1, Number(wf.visualPromptAttempt || j.visualPromptAttempt || 1));
  const maxAttempts = Math.max(2, Number(wf.visualPromptMaxAttempts || j.visualPromptMaxAttempts || 2));
  return { attempt, maxAttempts, canRetry: attempt < maxAttempts, vj, wf };
}

const j = $input.first().json || {};

function safeStr(v) {
  if (v === null || v === undefined) return "";
  return String(v).trim();
}

function parseMaybeJson(v) {
  if (!v) return {};
  if (typeof v === "object") return v;
  try { return JSON.parse(v); } catch (e) { return {}; }
}

// FIX 1.4: blocked_by_source_lock pass-through — kein KI-Aufruf, keine Pflichtfelder
if (safeStr(j.visualStage) === 'blocked_source_lock') {
  return [{
    json: {
      ...j,
      visualStage: 'blocked_source_lock',
      imageStage: (safeStr(j.imageFinalPath) ? 'composed' : 'not_started')
    }
  }];
}

// FIX 1.1: Retry-Zähler hier erhöhen, BEVOR Update allris_vorgaenge läuft
const errorStages = new Set(['prompt_error']);
if (errorStages.has(safeStr(j.visualStage))) {
  const { attempt, maxAttempts, vj, wf } = getRetryInfo(j);
  const newAttempt = attempt + 1;
  if (newAttempt > maxAttempts) {
    vj.workflow = { ...wf, visualPromptAttempt: newAttempt, visualPromptMaxAttempts: maxAttempts, visualPromptFinalStatus: 'visual_prompt_failed_final' };
    return [{
      json: {
        ...j,
        visualJson: JSON.stringify(vj),
        visualPromptAttempt: newAttempt,
        visualPromptMaxAttempts: maxAttempts,
        visualStage: 'prompt_failed_final',
        imageStage: (safeStr(j.imageFinalPath) ? 'composed' : 'not_started')
      }
    }];
  } else {
    vj.workflow = { ...wf, visualPromptAttempt: newAttempt, visualPromptMaxAttempts: maxAttempts };
    return [{
      json: {
        ...j,
        visualJson: JSON.stringify(vj),
        visualStage: safeStr(j.visualStage),
        imageStage: (safeStr(j.imageFinalPath) ? 'composed' : 'not_started'),
        visualPromptAttempt: newAttempt,
        visualPromptMaxAttempts: maxAttempts
      }
    }];
  }
}

// Fehler-Pass-Through: Bei visualParseError nicht werfen
if (j.visualParseError === true) {
  return [{
    json: {
      ...j,
      visualStage: j.visualStage || 'prompt_error',
      imageStage: (safeStr(j.imageFinalPath) ? 'composed' : 'not_started')
    }
  }];
}

const visualJson = parseMaybeJson(j.visualJson);

const imageHeadline =
  safeStr(j.imageHeadline) ||
  safeStr(visualJson.imageHeadline);

const imageSubline =
  safeStr(j.imageSubline) ||
  safeStr(visualJson.imageSubline);

const imageSmallNote = '';

const imagePrompt =
  safeStr(j.imagePrompt) ||
  safeStr(visualJson.imagePrompt);

const imageNegativePrompt =
  safeStr(j.imageNegativePrompt) ||
  safeStr(visualJson.imageNegativePrompt);

if (!imageHeadline) {
  throw new Error("imageHeadline fehlt.");
}
if (!imageSubline) {
  throw new Error("imageSubline fehlt.");
}
if (!imagePrompt) {
  throw new Error(
    "imagePrompt fehlt. Vorhandene Felder: " + Object.keys(j).join(", ")
  );
}

return [
  {
    json: {
      ...j,
      imageHeadline,
      imageSubline,
      imageSmallNote,
      imagePrompt,
      imageNegativePrompt,
      visualStage: safeStr(j.visualStage) || 'prompt_ready',
      imageStage: (safeStr(j.imageFinalPath) ? 'composed' : 'not_started')
    }
  }
];

// FIX 10: Prüfe Content-Abschluss - vollständige Prüfung (V3_11)
const j = $input.item.json || {};
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch(e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(s => String(s).trim());
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(s => String(s).trim()); } catch(e) {}
  }
  return [];
}
function robustBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') { const s = v.trim().toLowerCase(); return s === 'true' || s === '1'; }
  return false;
}

const forceVisualPromptReset = j._forceVisualPromptReset === true || j.visualForceReset === true;

const errors = [];

// 1. contentStage muss content_generated oder content_posted sein
const contentStage = safeStr(j.contentStage);
const contentStageOk = contentStage === 'content_generated' || contentStage === 'content_posted';
const contentStatusOk = contentStageOk || forceVisualPromptReset;
if (!contentStatusOk) errors.push('contentStage nicht content_generated/content_posted und kein Force-Reset (ist: ' + contentStage + ')');

// 2. contentJson muss vorhanden sein
const contentJson = parseObj(j.contentJson);
const contentPresent = !!(safeStr(j.websiteHeadline) || Object.keys(contentJson).length > 0);
if (!contentPresent) errors.push('contentJson fehlt oder leer');

// 3. sourceLockValid
const analysis = parseObj(j.analysisJson);
const slValidFlag = robustBool(analysis.sourceLockValid);
if (!slValidFlag) errors.push('sourceLockValid nicht true');

// 4. sourceLock vollständig (FIX 10: inkl. requiredObjects + requiredAction)
const sl = parseObj(analysis.sourceLock || {});
const slComplete = !!(
  safeStr(sl.sourceTopic) && safeStr(sl.sourceConflict) &&
  asArr(sl.requiredTerms).length >= 2 &&
  asArr(sl.requiredObjects).length >= 2 &&
  safeStr(sl.requiredAction) &&
  slValidFlag
);
if (!slComplete) errors.push('sourceLock unvollständig (requiredObjects/requiredAction prüfen)');

// 5. visualAnchors vollständig (FIX 10: inkl. visualVerboteneErsatzmotive >= 2 + visualAnchorsValid)
const vaValidFlag = robustBool(analysis.visualAnchorsValid);
const va = parseObj(analysis.visualAnchors || {});
const vaComplete = !!(
  safeStr(va.satireThemaKonkret) && safeStr(va.satireKonfliktKonkret) &&
  asArr(va.visualPflichtobjekte).length >= 2 &&
  safeStr(va.visualPflichthandlung) && safeStr(va.visualErkennungssatz) &&
  safeStr(va.visualUeberzeichnung) &&
  asArr(va.visualVerboteneErsatzmotive).length >= 2 &&
  vaValidFlag
);
if (!vaComplete) errors.push('visualAnchors unvollständig (visualVerboteneErsatzmotive/visualAnchorsValid prüfen)');

const contentGateOk = errors.length === 0;

return [{
  json: {
    ...j,
    _contentGateOk: contentGateOk,
    _contentGateErrors: errors,
    _contentGateForceReset: forceVisualPromptReset
  }
}];

// Sortierung: 1. firstseen aufsteigend, 2. volfdnr numerisch, 3. vorgangKey lexikografisch
function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}
function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}
const items = $input.all();
items.sort((a, b) => {
  const ja = a.json || {}, jb = b.json || {};
  const fa = parseDate(ja.firstseen), fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;
  const va = parseVolfdnr(ja.volfdnr), vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;
  return String(ja.vorgangKey || '').localeCompare(String(jb.vorgangKey || ''));
});
return items;

// ============================================================
// FORCE VISUAL PROMPT RESET SCHALTER
// Setzt alte Bildprompt-Felder vor der Content-Gate-Prüfung zurück.
// Standard: AUS. Sicherste Nutzung: In der DataTable visualStatus = "force_visual_reset" setzen.
// Optional: FORCE_RESET_VISUAL_PROMPT auf true setzen und mit VorgangKey/Vorgangsnummer begrenzen.
// ============================================================

const FORCE_RESET_VISUAL_PROMPT = false;      // nur kurzzeitig auf true setzen
const FORCE_ONLY_VORGANG_KEY = '';             // z.B. 'vol_10742' oder leer
const FORCE_ONLY_VORGANGSNUMMER = '';          // z.B. '2026/197' oder leer

const j = $input.item.json || {};

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function norm(v) {
  return safeStr(v).toLowerCase();
}

const vorgangKey = safeStr(j.vorgangKey);
const vorgangsnummer = safeStr(j.vorgangsnummer);

const resetByStatus = j.visualForceReset === true;
const hasTarget = !!(safeStr(FORCE_ONLY_VORGANG_KEY) || safeStr(FORCE_ONLY_VORGANGSNUMMER));
const targetMatches =
  (!safeStr(FORCE_ONLY_VORGANG_KEY) || vorgangKey === safeStr(FORCE_ONLY_VORGANG_KEY)) &&
  (!safeStr(FORCE_ONLY_VORGANGSNUMMER) || vorgangsnummer === safeStr(FORCE_ONLY_VORGANGSNUMMER));

// Sicherheitslogik:
// - visualStatus=force_visual_reset setzt immer genau diesen Datensatz zurück.
// - FORCE_RESET_VISUAL_PROMPT=true ohne Ziel setzt nur bereits geholte Kandidaten zurück.
// - Für gezieltes Zurücksetzen per Variable immer FORCE_ONLY_* setzen.
const resetByVariable = FORCE_RESET_VISUAL_PROMPT === true && (!hasTarget || targetMatches);
const doReset = resetByStatus || resetByVariable;

if (!doReset) {
  return [{ json: { ...j, _forceVisualPromptReset: false } }];
}

return [{
  json: {
    ...j,
    _forceVisualPromptReset: true,
    _forceVisualPromptResetAt: new Date().toISOString(),
    _forceVisualPromptResetReason: resetByStatus
      ? 'visualForceReset flag'
      : 'FORCE_RESET_VISUAL_PROMPT=true',

    // Wichtig: Status des Visual Prompt Builders wieder öffnen
    visualStage: 'needs_prompt',
    imageStage: 'not_started',

    // Alte Visual-Prompt-Artefakte entfernen, damit kein Skip greifen kann
    imagePrompt: '',
    imageNegativePrompt: '',
    imageHeadline: '',
    imageSubline: '',
    imageSmallNote: '',
    altText: '',
    visualJson: '{}',
    visualParseError: false,
    visualDebugReason: '',
    rawVisualText: '',

    // Nachgelagerte Bildartefakte entkoppeln, falls Spalten existieren
    imageFinalPath: '',
    imageCreatedAt: '',
    imageWorkflowVersion: '',

    // Interne Hinweise, falls Felder nicht als Spalten existieren: unschädlich im Laufzeit-JSON
    imagePromptFound: false,
    _skipReason: ''
  }
}];

// Cutover 2026-07-18: baut die Eingabe fuer den echten Bild-Agent-Aufruf, ersetzt P5s
// eigene 'AI Visual JSON'-Generierung. sourceTopic/requiredObjects/requiredAction/
// affectedGroups werden nirgends als eigene DB-Spalte persistiert - sie stecken im
// bereits gespeicherten faktenAgentJson (siehe P3-Cutover), deshalb hier von dort lesen.
// satireBrief/imageHeadline/imageSubline usw. sind bereits echte Top-Level-Spalten
// (Auto-Wahl aus P3 fuer den Text, ggf. durch P5bs Matrix-Umfrage fuers Bild ueberschrieben).
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(safeStr);
  if (typeof v === 'string' && v.trim()) { try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(safeStr); } catch (e) {} }
  return [];
}
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}

const row = $json;
const fakten = parseObj(row.faktenAgentJson);

return {
  json: {
    ...row,
    vorgangKey: safeStr(row.vorgangKey),
    vorgangsnummer: safeStr(row.vorgangsnummer),
    sourceTopic: safeStr(fakten.sourceTopic),
    requiredObjects: asArr(fakten.requiredObjects),
    requiredAction: safeStr(fakten.requiredAction),
    affectedGroups: asArr(fakten.affectedGroups),
    satireBrief: safeStr(row.satireBrief),
    satireAngle: safeStr(row.satireAngle),
    satirePunchlines: asArr(row.satirePunchlines),
    satireTarget: safeStr(row.satireTarget),
    satireIntensity: row.satireIntensity,
    satireDoNotClaim: asArr(row.satireDoNotClaim),
    satireSafetyNote: safeStr(row.satireSafetyNote),
    imageHeadline: safeStr(row.imageHeadline),
    imageSubline: safeStr(row.imageSubline)
  }
};

// Stellt den Vorgangskontext nach dem Bild-Agent-Aufruf wieder her (gleiches Muster wie
// die anderen 'Stelle Kontext nach ... Agent wieder her'-Nodes in P3) - Execute Workflow
// ersetzt das Item-JSON durch die reine Sub-Workflow-Antwort.
// Bei Parse-Fehler: visualParseError=true setzen, damit 'Code in JavaScript' den
// bestehenden, unveraenderten Fehler-/Retry-Pfad nimmt (visualStage='prompt_error'),
// statt beim fehlenden imagePrompt zu werfen.
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const response = $json || {};
const base = $('Bild-Agent: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasParseError = response.parseError === true || typeof response.imagePrompt !== 'string';

if (hasParseError) {
  return {
    json: {
      ...base,
      visualParseError: true,
      visualDebugReason: 'Bild-Agent Parse-Fehler oder Aufruf fehlgeschlagen',
      visualStage: 'prompt_error',
      imageStage: (safeStr(base.imageFinalPath) ? 'composed' : 'not_started'),
      visualPromptCreatedAt: new Date().toISOString()
    }
  };
}

return {
  json: {
    ...base,
    imageHeadline: safeStr(response.imageHeadline) || safeStr(base.imageHeadline),
    imageSubline: safeStr(response.imageSubline) || safeStr(base.imageSubline),
    imagePrompt: safeStr(response.imagePrompt),
    imageNegativePrompt: safeStr(response.imageNegativePrompt),
    altText: safeStr(response.altText),
    visualMetaphor: safeStr(response.visualMetaphor),
    visualParseError: false,
    visualDebugReason: '',
    visualStage: 'prompt_ready',
    imageStage: (safeStr(base.imageFinalPath) ? 'composed' : 'not_started'),
    visualPromptCreatedAt: new Date().toISOString()
  }
};
